text_0: f.text_0;

// --- locale (en/sk/de) ---
def lang = "en"
try { lang = (org.springframework.context.i18n.LocaleContextHolder.getLocale()?.getLanguage() ?: "en").toLowerCase() } catch(Throwable t){}
if(!(lang in ["en","sk","de"])) lang = "en"

// --- labels ---
def LABELS = [
  "en":[title:"List of invoices", name:"Invoice name", action:"Open task", created:"Created", open:"Open"],
  "sk":[title:"Zoznam faktúr",   name:"Názov faktúry", action:"Otvoriť úlohu", created:"Vytvorené", open:"Otvoriť"],
  "de":[title:"Rechnungen",       name:"Rechnungsname", action:"Aufgabe öffnen", created:"Erstellt", open:"Öffnen"]
]
def L = LABELS[lang] ?: LABELS["en"]

// --- create case + URL to t5 ---
def now   = new java.text.SimpleDateFormat("yyyy-MM-dd HH:mm").format(new java.util.Date())
def title = "Invoice from " + now
def myCase = createCase("lubospetrovic1383/invoice", title,"", userService.loggedOrSystem)

def myTask = findTask(myCase.tasks.find{it.transition == "t1"}.task);
assignTask(myTask, userService.loggedUser);
workflowService.save(myCase)


def caseId = myCase?.stringId ?: myCase?.id?.toString()
if(!caseId){
  // soft-fail: show an error note row instead of breaking the UI
  def err = (lang=="sk") ? "Nepodarilo sa vytvoriť prípad" : (lang=="de" ? "Fall konnte nicht erstellt werden" : "Could not create case")
  def htmlErr = "<div style='color:#b91c1c; padding:8px 0'>${err}</div>"
  change text_0 value { ((text_0.value?:'') + htmlErr) }
  return
}
def urlFromCase = "https://etask.netgrif.cloud/process/bHVib3NwZXRyb3ZpYzEzMTAwL2ludm9pY2U/" + caseId

// --- helpers ---
def esc = { s -> (s==null) ? "" : s.toString().replace("&","&amp;").replace("<","&lt;").replace(">","&gt;") }
def makeButton = { txt, href ->
  "<a href='${href}' target='_blank' rel='noopener' " +
  "style='display:inline-block;padding:6px 10px;border-radius:8px;border:1px solid #888;text-decoration:none'>" +
  esc(txt) + "</a>"
}

// --- ensure table exists ---
def html = (text_0.value ?: "").toString()
if(!html.contains('id="invoice_table"')){
  def head = """
  <div style='margin:8px 0;font-weight:600'>${esc(L.title)}</div>
  <table id="invoice_table" style="border-collapse:collapse;width:100%;font-family:system-ui,Segoe UI,Arial,sans-serif">
    <thead>
      <tr style="background:#f3f4f6">
        <th style="text-align:left;padding:8px;border:1px solid #ddd">${esc(L.name)}</th>
        <th style="text-align:left;padding:8px;border:1px solid #ddd">${esc(L.action)}</th>
        <th style="text-align:left;padding:8px;border:1px solid #ddd">${esc(L.created)}</th>
      </tr>
    </thead>
    <tbody>
    </tbody>
  </table>
  """.stripIndent()
  html = head
}

// --- append one row before </tbody> ---
def row = new java.lang.StringBuilder()
row.append("<tr>")
row.append("<td style='padding:8px;border:1px solid #ddd'>").append(esc(title)).append("</td>")
row.append("<td style='padding:8px;border:1px solid #ddd'>").append(makeButton(L.open, urlFromCase)).append("</td>")
row.append("<td style='padding:8px;border:1px solid #ddd'>").append(esc(now)).append("</td>")
row.append("</tr>")

int pos = html.indexOf("</tbody>")
if(pos > 0){
  html = html.substring(0, pos) + row.toString() + html.substring(pos)
} else {
  // fallback: no <tbody> found → just append after existing content
  html = html + row.toString()
}

// --- write back to htmltextarea ---
change text_0 value { html }
